VALUES
  ('judicial-0b5ab5d8-moex-00096', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依司法院釋字第609號解釋意旨，有關勞工保險，下列敘述何者正確？', '["勞工保險應謹守對價原則，以符合保險契約之本質", "勞工保險與商業保險相同，應由勞工保險局評估危險後決定是否簽訂保險契約", "勞工保險得由勞工保險局與被保險人自由約定保險契約，排除勞工保險條例的適用", "勞工保險條例之排除保險給付規定，得由立法機關依保險法理並參酌其他社會安全制度形成之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00097', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '關於刑法撤銷假釋之規定與人身自由之關係，下列敘述何者正確？', '["撤銷假釋之規定，對受假釋人之人身自由造成限制，故不得再執行殘刑", "撤銷假釋之規定，限制受假釋人之人身自由，屬憲法保留事項，故不得以法律定之", "撤銷假釋之規定，對受假釋人之人身自由造成限制，必須符合比例原則之要求", "撤銷假釋之規定，並未使受假釋人承受新刑罰，故並未限制受假釋人之人身自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00098', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依司法院大法官解釋，有關婚姻與家庭之保障，下列敘述何者錯誤？', '["婚姻與家庭制度應受制度性保障", "家庭制度之保障植根於人格自由", "人民收養子女之自由為憲法第22條所保障", "限制人民收養其配偶之大陸地區子女為違反平等權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00099', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '中央警察大學研究所碩士班入學考試招生簡章，以有無色盲決定能否取得入學資格之規定，依司法院釋字 第626號解釋，下列敘述何者錯誤？', '["相關入學資格條件之設定，為大學自治事項，於合理及必要之範圍內，不生違反法律保留之問題", "受國民教育以外教育之權利雖受憲法第22條所保障，但不包括賦予人民請求給予入學許可之權利", "警大自治權之行使，應受其功能本質之限制，且為確保其達成國家賦予之政策功能，而應接受比一般大 學更多之國家監督", "鑑於色盲非屬人力所得控制之生理缺陷，警察大學作為培養國家警察專門人才之學術單位，自不得以此 作為差別待遇標準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00100', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '法律規定汽車駕駛人駕車強行闖越鐵路平交道，因而肇事者，處新臺幣1萬5千元以上9萬元以下罰鍰， 並吊銷其駕駛執照，終身不得考領駕駛執照，並應接受道路交通安全講習。關於上開規定，依司法院釋字 第780號解釋，下列敘述何者錯誤？', '["處以罰鍰係對汽車駕駛人財產權之限制", "終身不得考領駕駛執照，係限制汽車駕駛人之一般行為自由", "如駕駛人為職業駕駛人，則吊銷其駕駛執照將涉及人民選擇職業自由之客觀條件限制", "強制駕駛人參加道路交通安全講習，係對人民一般行為自由之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00101', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '有關憲法第22條所稱「其他權利」，下列敘述何者正確？', '["「不妨礙社會秩序公共利益」應遵循社會多數意見作解釋", "本條之基本權利位階及效力較其他基本權劣後", "大法官依據本條而導出新聞自由之保障", "本條會隨著時代及社會的發展而進展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00102', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '下列何者尚未經司法院大法官解釋明白承認屬憲法財產權之保障範圍？', '["攜帶外幣出入國境須報明登記，違反者應予沒入", "主管機關就其徵收之土地，應定期通知原所有權人土地之後續使用情形", "政府採購得標廠商在符合一定要件下，應於履約期間僱用一定比例之原住民員工", "人民依法請求國家賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00103', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '依憲法訴訟法規定，人民不得針對下列何者聲請判決？', '["最高法院之不利確定終局裁定適用之法律", "最高行政法院之不利確定終局判決", "監察院之彈劾案", "地方自治團體制定之自治條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00104', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '在我國憲法體制之下，下列何者得行使憲法上之行政權？', '["總統", "立法院國防委員會", "監察院", "懲戒法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
  ('judicial-0b5ab5d8-moex-00105', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-111-3d2b73b6', 'sub-judicial-0b5ab5d8-08', NULL, 'single_choice', '有關國會質詢權之敘述，下列何者錯誤？', '["司法、考試、監察三院院長，得不受邀備詢，乃係基於憲政慣例", "參謀總長得不受邀備詢，乃係基於國防事務乃屬總統權限", "檢察官得不受邀備詢，乃係基於其依法獨立行使職權、不受外部干涉", "公平交易委員會委員得不受邀備詢，乃係基於其依法獨立行使職權、不受外部干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:05+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "108", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL)
